-- ============================================================
-- Tutr — LAU Course Table RESET
-- Wipes ALL LAU courses and re-inserts the real 534-course
-- catalog from catalog.lau.edu.lb 2025-2026.
--
-- Cascading effect: any tutor_courses, sessions, requests, or
-- reviews that referenced old LAU courses will also be deleted.
-- This is safe for demo data.
--
-- Run this ONCE in the Supabase SQL Editor.
-- ============================================================

-- Step 1: wipe all LAU courses (cascades to dependent tables)
delete from public.courses where university_id = 'lau';

-- Step 2: insert all 534 real LAU courses
insert into public.courses (id, code, name, university_id, subject, description, credits, prerequisites, typical_semester) values

